var import_obsidian5 = require("obsidian");
var GalleryBlockGenerateModal = class extends import_obsidian5.Modal {
  constructor(app, selectedText) {
    super(app);
    this.title = "";
    this.size = "medium";
    this.addButton = false;
    this.pagination = 0;
    this.selectedText = this.parseExistingContent(selectedText);
    this.replaceRange = null;
    this.onConfirm = null;
  }
  // 解析現有的 gallery 區塊內容
  parseExistingContent(content) {
    const lines = content.split("\n");
    let mediaItems = "";
    for (const line of lines) {
      const trimmedLine = line.trim();
      const titleMatch = trimmedLine.match(/^title:\s*(.+)$/);
      if (titleMatch) {
        this.title = titleMatch[1];
        continue;
      }
      const sizeMatch = trimmedLine.match(/^size:\s*(small|medium|large)$/i);
      if (sizeMatch) {
        this.size = sizeMatch[1].toLowerCase();
        continue;
      }
      const addButtonMatch = trimmedLine.match(/^addbutton:\s*(true|false)$/i);
      if (addButtonMatch) {
        this.addButton = addButtonMatch[1].toLowerCase() === "true";
        continue;
      }
      const paginationMatch = trimmedLine.match(/^pagination:\s*(\d+)$/i);
      if (paginationMatch) {
        this.pagination = parseInt(paginationMatch[1]) || 0;
        continue;
      }
      if (!trimmedLine.match(/^(title|size|addbutton|pagination):/i) && trimmedLine) {
        mediaItems += line + "\n";
      }
    }
    return mediaItems.trim();
  }
  onOpen() {
    const { contentEl } = this;
    new import_obsidian5.Setting(contentEl).setName(t("gallery_title")).setDesc(t("gallery_title_desc")).addText((text) => text.setValue(this.title || "").onChange((value) => this.title = value));
    new import_obsidian5.Setting(contentEl).setName(t("gallery_size")).setDesc(t("gallery_size_desc")).addDropdown((dropdown) => dropdown.addOption("small", t("grid_size_small")).addOption("medium", t("grid_size_medium")).addOption("large", t("grid_size_large")).setValue(this.size).onChange((value) => this.size = value));
    new import_obsidian5.Setting(contentEl).setName(t("gallery_add_button")).setDesc(t("gallery_add_button_desc")).addToggle((toggle) => toggle.setValue(this.addButton).onChange((value) => this.addButton = value));
    new import_obsidian5.Setting(contentEl).setName(t("gallery_pagination")).setDesc(t("gallery_pagination_desc")).addText((text) => text.setValue(this.pagination ? this.pagination.toString() : "").setPlaceholder("0").onChange((value) => {
      const numValue = parseInt(value);
      this.pagination = !isNaN(numValue) && numValue > 0 ? numValue : 0;
    }));
    new import_obsidian5.Setting(contentEl).addButton((button) => button.setButtonText(t("confirm")).setCta().onClick(() => {
      const galleryBlock = ["```gallery"];
      if (this.title !== "")
        galleryBlock.push(`title: ${this.title}`);
      if (this.size !== "medium")
        galleryBlock.push(`size: ${this.size}`);
      if (this.addButton)
        galleryBlock.push(`addButton: ${this.addButton}`);
      if (this.pagination > 0)
        galleryBlock.push(`pagination: ${this.pagination}`);
      if (this.selectedText)
        galleryBlock.push(this.selectedText);
      galleryBlock.push("```\n");
      const newGalleryBlockContent = galleryBlock.join("\n");
      if (this.onConfirm) {
        this.onConfirm(newGalleryBlockContent.trim());
      }
      this.close();
    }));
  }
  onClose() {
    const { contentEl } = this;
    contentEl.empty();
  }
};

